diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..c3775ac5513f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8633,14 +8633,27 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   Constant *RHSC;
   if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
     switch (LHSI->getOpcode()) {
-    case Instruction::Select:
+    case Instruction::Select: {
       // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0), X, 0), C --> fcmp oeq X, C
+      // If X is NaN, select returns 0, and fcmp oeq 0, C is false (assuming C != 0).
+      // But fcmp oeq NaN, C is also false. If X is ordered, select returns X.
+      // So the whole expression is equivalent to just fcmp oeq X, C.
+      if (Pred == FCmpInst::FCMP_OEQ) {
+        CmpPredicate SelPred;
+        if (match(LHSI, m_Select(m_FCmp(SelPred, m_Value(X), m_AnyZeroFP()),
+                                 m_Deferred(X), m_AnyZeroFP())) &&
+            SelPred == FCmpInst::FCMP_ORD)
+          return replaceOperand(I, 0, X);
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
+    }
+      break;
     case Instruction::FSub:
       if (LHSI->hasOneUse())
         if (Instruction *NV = foldFCmpFSubIntoFCmp(I, LHSI, RHSC, *this))

